While testing some JSON features we noticed a change in the value returned by `Decoder.InputOffset()` between running the snippet in gotip and go 1.26. 

```
package main

import (
	"encoding/json"
	"fmt"
	"io"
	"strings"
)

func main() {
	const input = `{"key": `
	fmt.Printf("input: %q\n\n", input)

	dec := json.NewDecoder(strings.NewReader(input))

	for {
		tok, err := dec.Token()
		if err == io.EOF {
			break
		}
		if err != nil {
			panic("should not reach here")
		}
		fmt.Printf("Scanned Token: %v\t | Type: %T\t | InputOffset: %d\n", tok, tok, dec.InputOffset())
	}

	fmt.Printf("\nFinal InputOffset : %d\n", dec.InputOffset())
	fmt.Printf("Sliced Inputstr   : %q\n", input[:dec.InputOffset()])
}
```

Playground: https://go.dev/play/p/Raaoz1j4RcB

What we see: `Final InputOffset : 6`

What we expected to see (as in go 1.26): `Final InputOffset : 7`
